function candidate(input, extension) {
  if (typeof input !== 'string') {
    throw new TypeError('The path argument must be of type string. Received ' + typeof input);
  }
  if (arguments.length > 1 && typeof extension !== 'string') {
    throw new TypeError('The ext argument must be of type string. Received ' + typeof extension);
  }

  if (arguments.length > 1 && extension === input) {
    return '';
  }

  let end = input.length - 1;
  while (end >= 0 && input.charCodeAt(end) === 47) {
    end--;
  }
  if (end < 0) {
    return '';
  }

  let start = end;
  while (start >= 0 && input.charCodeAt(start) !== 47) {
    start--;
  }

  const segment = input.slice(start + 1, end + 1);
  if (
    arguments.length > 1 &&
    extension.length > 0 &&
    extension.length < segment.length &&
    segment.endsWith(extension)
  ) {
    return segment.slice(0, segment.length - extension.length);
  }

  return segment;
}
